mapper.select:
SELECT COUNT(*)
FROM SCOTT.post_like
WHERE account_id = #{accountId, jdbcType=NUMERIC}
  AND post_id    = #{postId, jdbcType=NUMERIC}

mapper.delete:
DELETE FROM SCOTT.post_like
WHERE account_id = #{accountId, jdbcType=NUMERIC}
  AND post_id    = #{postId, jdbcType=NUMERIC}

mapper.select:
SELECT account_id
FROM SCOTT.posts
WHERE post_id = #{postId, jdbcType=NUMERIC}
